SELECT ?actor WHERE {
  ?work wdt:P1476 "The Phantom of the Opera" ;
         wdt:P31 wd:Q11424 .
  ?work p:P161 [ ps:P161 ?actor ;
                 pq:P161 wd:Q57680143 ].
}

SELECT ?actor ?actorLabel WHERE {
  ?work wdt:P1476 "The Phantom of the Opera" ;
        wdt:P31 wd:Q11424 ;
        wdt:P577 ?year.
  ?work wdt:P161 ?actor.
  ?actor rdfs:label ?actorLabel.
  FILTER (langMatches(lang(?actorLabel), "en"))
}
ORDER BY ASC(?year)
LIMIT 1

